115	                    Logs
116	                  </Link>
117	                </li>
118	                <li className="pf-v6-c-nav__item">
119	                  <Link className="pf-v6-c-nav__link" to="/monitoring/alerts/test-alert">
120	                    Alerts
121	                  </Link>
122	                </li>
123	              </ul>
124	            </nav>
125	          </div>
