132	            <Route path="/k8s/ns/:ns/pods/:name" element={<LogsDetailPage />} />
133	            <Route
134	              path="/monitoring/alerts/:alertname"
135	              element={
136	                <LogsAlertMetrics
137	                  rule={{
138	                    labels: { tenantId: 'application' },
139	                    query: `sum by(job)(rate({ job=~".+" }[5m])) > 0`,
140	                  }}
141	                />
142	              }
143	            />
144	          </Routes>
145	        </main>
146	      </BrowserRouter>
147	    </div>
148	  );
149	};
