 8	export const checkErrors = () =>
 9	  cy.window().then((win) => {
10	    assert.isTrue(!win.windowError, win.windowError);
11	  });
12	
13	  // Ignore benign ResizeObserver errors globally so they don't fail tests
14	// See: https://docs.cypress.io/api/cypress-api/catalog-of-events#Uncaught-Exceptions
15	Cypress.on('uncaught:exception', (err) => {
16	  const message = err?.message || String(err || '');
17	  if (
18	    message.includes('ResizeObserver loop limit exceeded') ||
19	    message.includes('ResizeObserver loop completed with undelivered notifications') ||
20	    message.includes('ResizeObserver') ||
21	    message.includes('Cannot read properties of undefined') ||
22	    message.includes('Unauthorized') ||
23	    message.includes('Bad Gateway') ||
24	    message.includes(`Cannot read properties of null (reading 'default')`) ||
25	    message.includes(`(intermediate value) is not a function`)
26	  ) {
27	    console.warn('Ignored frontend exception:', err.message);
28	    return false;
29	  }
30	  // allow other errors to fail the test
31	});
32	
33	
34	
35	Cypress.on('uncaught:exception', (err) => {
36	  console.error("Uncaught error:", err.message);
